"use client";

import React, { useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '@/lib/firebase';
import { useAuth } from '@/context/AuthContext';
import { LogIn, Mail, Lock, AlertCircle, Loader2, Eye, EyeOff } from 'lucide-react';
import { usersApi } from '@/lib/api';

export default function LoginPage() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [forgotMode, setForgotMode] = useState(false);
    const [successMsg, setSuccessMsg] = useState<string | null>(null);

    const router = useRouter();
    const { refreshRole } = useAuth();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);
        setSuccessMsg(null);

        try {
            const userCredential = await signInWithEmailAndPassword(auth, email, password);
            const tokenResult = await userCredential.user.getIdTokenResult();

            // Refresh role in context as well
            await refreshRole();

            if (tokenResult.claims.role === 'ADMIN') {
                router.push('/admin');
            } else {
                router.push('/');
            }
        } catch (err: any) {
            console.error('Login error:', err);
            setError(err.message || 'Failed to login. Please check your credentials.');
        } finally {
            setLoading(false);
        }
    };

    const handleForgotPassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);
        setSuccessMsg(null);

        try {
            await usersApi.forgotPassword(email);
            setSuccessMsg('A password reset link has been generated. In a production app, this would be sent to your email.');
        } catch (err: any) {
            setError(err.message || 'Failed to process request.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <main className="min-vh-100 d-flex align-items-center justify-content-center bg-light py-5">
            <div className="container">
                <div className="row justify-content-center">
                    <div className="col-12 col-md-8 col-lg-5">
                        <div className="card border-0 shadow-lg rounded-4 overflow-hidden">
                            <div className="row g-0">
                                <div className="col-12 p-5 bg-white">
                                    <div className="text-center mb-5">
                                        <Link href="/">
                                            <img src="/images/resources/logo.png" alt="Logo" className="mb-4" style={{ height: '60px' }} />
                                        </Link>
                                        <h2 className="fw-bold text-dark">{forgotMode ? 'Reset Password' : 'Welcome Back'}</h2>
                                        <p className="text-secondary">
                                            {forgotMode
                                                ? 'Enter your email to receive a reset link'
                                                : 'Securely login to your Life Comrades account'}
                                        </p>
                                    </div>

                                    {error && (
                                        <div className="alert alert-danger d-flex align-items-center gap-2 rounded-3 border-0 py-3 mb-4">
                                            <AlertCircle size={20} />
                                            <span className="small">{error}</span>
                                        </div>
                                    )}

                                    {successMsg && (
                                        <div className="alert alert-success d-flex align-items-center gap-2 rounded-3 border-0 py-3 mb-4">
                                            <AlertCircle size={20} />
                                            <span className="small">{successMsg}</span>
                                        </div>
                                    )}

                                    <form onSubmit={forgotMode ? handleForgotPassword : handleLogin}>
                                        <div className="mb-4">
                                            <label className="form-label small fw-bold text-secondary text-uppercase mb-2">Email Address</label>
                                            <div className="input-group input-group-lg border rounded-3 overflow-hidden">
                                                <span className="input-group-text bg-white border-0 text-muted ps-3 pe-2">
                                                    <Mail size={20} />
                                                </span>
                                                <input
                                                    type="email"
                                                    className="form-control border-0 bg-white ps-2 shadow-none"
                                                    placeholder="name@example.com"
                                                    value={email}
                                                    onChange={(e) => setEmail(e.target.value)}
                                                    required
                                                />
                                            </div>
                                        </div>

                                        {!forgotMode && (
                                            <div className="mb-4">
                                                <div className="d-flex justify-content-between align-items-center mb-2">
                                                    <label className="form-label small fw-bold text-secondary text-uppercase mb-0">Password</label>
                                                    <button
                                                        type="button"
                                                        onClick={() => setForgotMode(true)}
                                                        className="btn btn-link p-0 text-decoration-none small fw-bold"
                                                        style={{ color: '#0D9488' }}
                                                    >
                                                        Forgot Password?
                                                    </button>
                                                </div>
                                                <div className="input-group input-group-lg border rounded-3 overflow-hidden transition-all focus-within:border-teal-500/50">
                                                    <span className="input-group-text bg-white border-0 text-muted ps-3 pe-2">
                                                        <Lock size={20} />
                                                    </span>
                                                    <input
                                                        type={showPassword ? "text" : "password"}
                                                        className="form-control border-0 bg-white ps-2 shadow-none"
                                                        placeholder="••••••••"
                                                        value={password}
                                                        onChange={(e) => setPassword(e.target.value)}
                                                        required={!forgotMode}
                                                    />
                                                    <button
                                                        type="button"
                                                        onClick={() => setShowPassword(!showPassword)}
                                                        className="input-group-text bg-white border-0 text-muted px-3 hover:text-teal-600 transition-colors"
                                                    >
                                                        {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                                                    </button>
                                                </div>
                                            </div>
                                        )}

                                        <button
                                            type="submit"
                                            disabled={loading}
                                            className="btn btn-primary w-100 py-3 rounded-3 fw-bold d-flex align-items-center justify-content-center gap-2 mb-4"
                                            style={{ backgroundColor: '#0D9488', border: 'none' }}
                                        >
                                            {loading ? (
                                                <Loader2 className="animate-spin" size={20} />
                                            ) : (
                                                <>
                                                    {forgotMode ? 'Send Reset Link' : 'Sign In'}
                                                    {!forgotMode && <LogIn size={20} />}
                                                </>
                                            )}
                                        </button>

                                        {forgotMode && (
                                            <div className="text-center">
                                                <button
                                                    type="button"
                                                    onClick={() => {
                                                        setForgotMode(false);
                                                        setError(null);
                                                        setSuccessMsg(null);
                                                    }}
                                                    className="btn btn-link text-decoration-none small fw-bold text-secondary"
                                                >
                                                    Back to Login
                                                </button>
                                            </div>
                                        )}
                                    </form>
                                </div>
                            </div>
                        </div>

                        <div className="text-center mt-4">
                            <p className="text-secondary small">
                                Don't have an account? <span className="fw-bold" style={{ color: '#0D9488' }}>Contact Support</span>
                            </p>
                        </div>
                    </div>
                </div>
            </div>
            <style jsx>{`
                .animate-spin {
                    animation: spin 1s linear infinite;
                }
                @keyframes spin {
                    from { transform: rotate(0deg); }
                    to { transform: rotate(360deg); }
                }
            `}</style>
        </main>
    );
}
